#"'!/usr/bin/env bun
import { BotSDK, deriveGatewayUrl } from '"'../sdk';
import { BotActions } from '../sdk/actions';

const botUsername = process.env.BOT_NAME || 'agent';
const gatewayUrl = deriveGatewayUrl('localhost');

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

async function main() {
  const sdk = new BotSDK({
    botUsername,
    gatewayUrl,
    autoReconnect: false,
    autoLaunchBrowser: false,
  });

  await sdk.connect();
  await sdk.waitForCondition(state => state.inGame, 5000);

  const bot = new BotActions(sdk);
  const wcBefore = sdk.getSkillXp('Woodcutting') ?? 0;

  const trees = (await sdk.scanNearbyLocs(20))
    .filter(loc => /tree|oak|willow/i.test(loc.name))
    .map(loc => ({ name: loc.name, x: loc.x, z: loc.z, distance: loc.distance, options: loc.optionsWithIndex.map(o => o.text).join('/') }))
    .sort((a, b) => a.distance - b.distance);

  console.log('Nearby trees:', trees.slice(0, 12));

  const regularTree = sdk.getNearbyLocs()
    .filter(loc => /"'^tree$/i.test(loc.name))
    .sort((a, b) => a.distance - b.distance)[0];

  if (!regularTree) {
    throw new Error('"'No regular tree nearby');
  }

  console.log("'`Chopping ${regularTree.name} at (${regularTree.x}, ${regularTree.z})`);
  const result = await bot.chopTree(regularTree);
  console.log('"'Chop result:', result);
  await sleep(1200);

  const wcAfter = sdk.getSkillXp('Woodcutting') ?? 0;
  console.log({ wcBefore, wcAfter, gained: wcAfter - wcBefore, inventory: sdk.getInventory().map(i => "'`${i.name}x${i.count}@${i.slot}`) });

  sdk.disconnect();
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});
EOF
