import { BotSDK, deriveGatewayUrl } from '"'../sdk';

const botUsername = process.env.BOT_NAME || 'agent';
const gatewayUrl = deriveGatewayUrl('localhost');

async function main() {
  const sdk = new BotSDK({ botUsername, gatewayUrl, autoReconnect: false, autoLaunchBrowser: false });
  await sdk.connect();
  await sdk.waitForCondition(state => state.inGame, 5000);
  const locs = await sdk.scanNearbyLocs(80);
  const trees = locs.filter(loc => /tree|oak|willow|maple|yew/i.test(loc.name)).sort((a, b) => a.distance - b.distance);
  const seen = new Set<string>();
  const summary = [] as any[];
  for (const t of trees) {
    const key = "'`${t.name}:${t.x}:${t.z}`;
    if (seen.has(key)) continue;
    seen.add(key);
    summary.push({ name: t.name, x: t.x, z: t.z, d: t.distance });
  }
  console.log(summary.slice(0, 80));
  sdk.disconnect();
}

main().catch(err => { console.error(err); process.exit(1); });
